// Canvas color application
function setCanvasColor(ctx, hexColor) {
  const [r, g, b] = getColorRgbList(hexColor);
  if (r !== undefined) {
    ctx.fillStyle = `rgb(${r}, ${g}, ${b})`;
    ctx.fillRect(0, 0, 100, 100);
  } else {
    console.error('Invalid color format');
  }
}

